import{_ as o,o as a,c as e,ak as n,f7 as l,f8 as p}from"./chunks/framework.DLt_otXO.js";const b=JSON.parse('{"title":"值类型和引用类型赋值","description":"","frontmatter":{"title":"值类型和引用类型赋值","date":"2022-01-14T15:49:39.000Z","permalink":"/pages/d5740d/","categories":["知识碎片"],"tags":[null]},"headers":[],"relativePath":"知识碎片/值类型和引用类型赋值.md","filePath":"知识碎片/值类型和引用类型赋值.md","lastUpdated":1777258973000}'),c={name:"知识碎片/值类型和引用类型赋值.md"};function t(r,s,d,i,E,y){return a(),e("div",null,[...s[0]||(s[0]=[n(`<h2 id="_1-js-中赋值" tabindex="-1">1.JS 中赋值 <a class="header-anchor" href="#_1-js-中赋值" aria-label="Permalink to “1.JS 中赋值”">​</a></h2><p>js 中数据类型分为<code>值类型</code>(基本类型)和<code>引用类型</code>。</p><ul><li><ol><li>值类型 如 ：<code>String</code>，<code>Number</code>，<code>Boolean</code>，<code>Undefined</code>，<code>Null</code></li></ol></li><li><ol start="2"><li>引用类型 如 ：<code>Object</code>，<code>Array</code></li></ol></li></ul><p><code>值类型</code>的数据保存在<code>栈内存</code>中。<code>引用类型</code>的数据保存在<code>堆内存</code>中。</p><h3 id="值类型赋值" tabindex="-1">值类型赋值 <a class="header-anchor" href="#值类型赋值" aria-label="Permalink to “值类型赋值”">​</a></h3><p>值类型赋值赋的是栈内存中具体的<code>值</code></p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">let</span><span style="color:#E1E4E8;"> a </span><span style="color:#F97583;">=</span><span style="color:#79B8FF;"> 100</span><span style="color:#E1E4E8;">;</span></span>
<span class="line"><span style="color:#F97583;">let</span><span style="color:#E1E4E8;"> b </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> a;</span></span>
<span class="line"><span style="color:#E1E4E8;">a </span><span style="color:#F97583;">=</span><span style="color:#79B8FF;"> 50</span><span style="color:#E1E4E8;">;</span></span>
<span class="line"><span style="color:#E1E4E8;">console.</span><span style="color:#B392F0;">log</span><span style="color:#E1E4E8;">(a); </span><span style="color:#6A737D;">// 50</span></span></code></pre></div><p>基本类型数据存放在<code>栈内存</code>中，访问是按<code>值</code>访问的，就是说你可以操作保存在变量中的实际的值。当基本类型的数据赋值时，赋的是实际的值，a 和 b 是没有关联关系的，b 由 a 复制得到，相互独立。所以下面的结果打印 50。 <img src="`+l+`"></p><h3 id="引用类型赋值" tabindex="-1">引用类型赋值 <a class="header-anchor" href="#引用类型赋值" aria-label="Permalink to “引用类型赋值”">​</a></h3><p>引用类型赋值，赋的是对象在栈内存中的<code>地址</code></p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki github-dark" style="background-color:#24292e;color:#e1e4e8;" tabindex="0" dir="ltr"><code><span class="line"><span style="color:#F97583;">let</span><span style="color:#E1E4E8;"> obj </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> { name: </span><span style="color:#9ECBFF;">&quot;小李&quot;</span><span style="color:#E1E4E8;">, age: </span><span style="color:#79B8FF;">18</span><span style="color:#E1E4E8;"> };</span></span>
<span class="line"><span style="color:#F97583;">let</span><span style="color:#E1E4E8;"> obj2 </span><span style="color:#F97583;">=</span><span style="color:#E1E4E8;"> obj;</span></span>
<span class="line"><span style="color:#E1E4E8;">obj.name </span><span style="color:#F97583;">=</span><span style="color:#9ECBFF;"> &quot;小刘&quot;</span><span style="color:#E1E4E8;">;</span></span>
<span class="line"><span style="color:#E1E4E8;">console.</span><span style="color:#B392F0;">log</span><span style="color:#E1E4E8;">(obj2.name); </span><span style="color:#6A737D;">// 小刘</span></span></code></pre></div><p>引用类型数据存放的方式是：</p><p>在<strong>栈内存</strong>中存放该对象的<strong>地址</strong>。在<strong>堆内存</strong>中存放该对象的<strong>数据</strong></p><p>该例子中，<code>obj</code>将自己在占内存中的地址赋值给<code>obj2</code>，此时它们同时指向<code>堆内存</code>地址的数据，修改它们其中的一个，数据虽然 变化了，但是它们的地址没有变，指向的还是同一个堆内存的数据，因此当 obj 修改数据的时候，obj2 也会变化。</p><img src="`+p+'">',15)])])}const g=o(c,[["render",t]]);export{b as __pageData,g as default};
